export const EXTENDED_PRAYER_TOPICS: PrayerTopic[] = [

  // ── SPECIFIC HEALTH CONDITIONS ──────────────────────────────────────────

  { slug:"diabetes", title:"Prayer for Diabetes", metaDesc:"A prayer for those living with diabetes — for healing, discipline, and God's strength to manage this condition daily.", category:"Health", keywords:["prayer for diabetes","diabetic prayer","prayer for blood sugar","prayer for type 2 diabetes"], samplePrayer:"Lord, You are Jehovah Rapha, the God who heals. I bring this condition called diabetes before You. Regulate what doctors cannot fully control. Give wisdom for diet, discipline for lifestyle, and supernatural intervention where medicine reaches its limit. Let my body respond to healing. I am not defined by this diagnosis — I am defined by Your Word. By Your stripes I am healed. In Jesus' name, Amen.", scripture:[{ref:"Psalm 103:3",text:"Who forgives all your sins and heals all your diseases."},{ref:"Isaiah 41:10",text:"I will strengthen you and help you."}], related:["healing","chronic-pain","strength","recovery","health-discipline"] },

  { slug:"heart-disease", title:"Prayer for Heart Disease", metaDesc:"A powerful prayer for healing from heart disease, heart attack recovery, and cardiac health.", category:"Health", keywords:["prayer for heart disease","prayer after heart attack","prayer for heart health","cardiac prayer"], samplePrayer:"Father, You hold every heartbeat in Your hands. You formed this heart and You can restore it. I pray against every blockage, every weakness, every malfunction in this heart. Let it beat strong and steady as You designed it to. Guide the cardiologists, bless the treatments, and let supernatural healing flow. You are greater than every diagnosis. In Jesus' name, Amen.", scripture:[{ref:"Ezekiel 36:26",text:"I will give you a new heart and put a new spirit in you."},{ref:"Psalm 34:18",text:"The Lord is close to the brokenhearted."}], related:["healing","hospital","surgery","recovery","strength"] },

  { slug:"stroke", title:"Prayer for Stroke Recovery", metaDesc:"A prayer for stroke survivors — for full recovery, restored speech, movement, and God's miraculous healing.", category:"Health", keywords:["prayer for stroke","stroke recovery prayer","prayer after stroke","prayer for stroke patient"], samplePrayer:"God of restoration, what a stroke has taken, I believe You can restore. Reconnect every neural pathway. Restore speech, movement, memory, and function. Let therapists and doctors see progress that surpasses expectation. You are the same God who said 'take up your mat and walk.' I stand on that truth. Full recovery is possible with You. In Jesus' name, Amen.", scripture:[{ref:"Jeremiah 30:17",text:"I will restore your health and heal your wounds."},{ref:"Psalm 30:2",text:"Lord my God, I called to you for help, and you healed me."}], related:["healing","hospital","recovery","mental-healing","strength"] },

  { slug:"high-blood-pressure", title:"Prayer for High Blood Pressure", metaDesc:"A prayer for healing from hypertension and high blood pressure. Trust God for peace that regulates body and mind.", category:"Health", keywords:["prayer for high blood pressure","prayer for hypertension","blood pressure prayer"], samplePrayer:"Prince of Peace, Your peace surpasses all understanding — and I believe it can regulate my blood pressure. Cast out every spirit of anxiety driving it up. Calm every vessel, every artery, every system in my body. Give me wisdom about diet, rest, and stress. And let Your supernatural peace guard my heart and my health. In Jesus' name, Amen.", scripture:[{ref:"Philippians 4:7",text:"The peace of God will guard your hearts and your minds."},{ref:"Isaiah 26:3",text:"You will keep in perfect peace those whose minds are steadfast."}], related:["healing","anxiety","stress","peace","recovery"] },

  { slug:"kidney-disease", title:"Prayer for Kidney Disease", metaDesc:"A prayer for healing from kidney disease, kidney failure, and for those on dialysis — trust God for restoration.", category:"Health", keywords:["prayer for kidney disease","dialysis prayer","kidney failure prayer","prayer for kidneys"], samplePrayer:"Lord, You designed every organ in this body with precision and purpose. I pray for these kidneys — that they would be cleansed, restored, and renewed. For those on dialysis, let each session go well and let God do what dialysis alone cannot. A transplant may come, or a miracle — either way You are the source of all healing. In Jesus' name, Amen.", scripture:[{ref:"Psalm 139:14",text:"I am fearfully and wonderfully made."},{ref:"3 John 1:2",text:"I pray that you may enjoy good health."}], related:["healing","hospital","recovery","chronic-pain","faith"] },

  { slug:"cancer-prayer", title:"Prayer Against Cancer", metaDesc:"A bold prayer against cancer for complete healing, victory in treatment, and God's miraculous power over every tumor.", category:"Health", keywords:["prayer against cancer","cancer prayer","prayer for cancer healing","prayer for tumor to shrink"], samplePrayer:"Father, cancer is a thief — and Your Word says the thief is defeated. I command every cancerous cell to shrink and die in the name of Jesus. Let chemotherapy, radiation, or surgery work far beyond their natural capacity. Strengthen the immune system. Let scans show what God has done. No weapon formed against this body shall prosper. Cancer does not have the final word — You do. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 54:17",text:"No weapon formed against you will prevail."},{ref:"Matthew 8:17",text:"He took up our infirmities and bore our diseases."}], related:["healing","healing-for-cancer","hospital","strength","hope"] },

  { slug:"alzheimers", title:"Prayer for Alzheimer's and Dementia", metaDesc:"A prayer for those suffering from Alzheimer's or dementia, and for their caregivers — God remembers even when we forget.", category:"Health", keywords:["prayer for Alzheimers","prayer for dementia","prayer for memory loss","prayer for caregiver"], samplePrayer:"Lord, even when memories fade, You do not forget. Every person with Alzheimer's is fully known and fully loved by You. Slow the progression. Give moments of clarity. Comfort the family watching their loved one fade. Give caregivers supernatural patience and strength. And remind us all that our identity is not in our memories but in Yours. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 49:15",text:"I will not forget you! See, I have engraved you on the palms of my hands."},{ref:"Psalm 71:9",text:"Do not cast me away when I am old."}], related:["elderly","sick-loved-one","healing","caregiver","comfort"] },

  { slug:"caregiver", title:"Prayer for Caregivers", metaDesc:"A prayer for those who care for the sick, elderly, or disabled. God sees your sacrifice and gives strength to carry on.", category:"Health", keywords:["prayer for caregivers","caregiver prayer","prayer for family caregiver","caregiver burnout prayer"], samplePrayer:"Lord, caregiving is one of the most demanding callings in life. The one giving care often has no one to care for them. I lift up every caregiver today — exhausted, overlooked, and stretched thin. Refill what has been poured out. Send help and support. Let them feel Your presence in the hard moments. Their labor is worship. In Jesus' name, Amen.", scripture:[{ref:"Galatians 6:9",text:"Let us not become weary in doing good."},{ref:"Isaiah 40:31",text:"Those who hope in the Lord will renew their strength."}], related:["elderly","sick-loved-one","burnout","strength","healing"] },

  { slug:"autoimmune", title:"Prayer for Autoimmune Disease", metaDesc:"A prayer for healing from autoimmune disease — lupus, MS, rheumatoid arthritis, and other conditions where the body attacks itself.", category:"Health", keywords:["prayer for autoimmune disease","prayer for lupus","prayer for rheumatoid arthritis","prayer for MS","prayer for multiple sclerosis"], samplePrayer:"Father, when the body fights itself, I bring it to You — the One who brings perfect peace and order. Speak to this immune system. Tell it to stand down from attacking what You created. Restore harmony in this body. Let every inflammation subside. Let every flare-up cease at the Word of God. Healing flows from You and I receive it. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 53:5",text:"By his wounds we are healed."},{ref:"Jeremiah 17:14",text:"Heal me, Lord, and I will be healed."}], related:["healing","chronic-pain","recovery","strength","faith"] },

  { slug:"terminal-illness", title:"Prayer for Terminal Illness", metaDesc:"A prayer for those facing terminal illness — for miraculous healing or a peaceful transition, and God's comfort through it all.", category:"Health", keywords:["prayer for terminal illness","prayer for dying","terminal cancer prayer","prayer for end of life"], samplePrayer:"God, in the face of a terminal diagnosis, I still believe You are able. I pray for a miracle — I pray for reversal. But I also surrender to Your sovereignty. Whether healing comes here or in eternity, let peace govern this season. Let pain be managed, let love be felt, and let Your presence be undeniable in this valley. We trust You. In Jesus' name, Amen.", scripture:[{ref:"Romans 8:38-39",text:"Nothing will be able to separate us from the love of God."},{ref:"Psalm 23:4",text:"Even though I walk through the darkest valley, I fear no evil."}], related:["comfort","hope","loss-of-loved-one","healing","funeral"] },

  { slug:"epilepsy", title:"Prayer for Epilepsy", metaDesc:"A prayer for healing from epilepsy and seizures — commanding the brain to be still in the name of Jesus.", category:"Health", keywords:["prayer for epilepsy","seizure prayer","prayer for seizures","prayer for epileptic child"], samplePrayer:"Lord, You spoke and the storm was still. I speak to this brain right now — be still. Let every misfiring neuron come under the authority of Jesus Christ. No more seizures. No more episodes. The same power that calmed the sea can calm every electrical storm in this brain. I command healing and wholeness in Jesus' mighty name, Amen.", scripture:[{ref:"Mark 4:39",text:"He said to the waves, 'Quiet! Be still!' Then the wind died down."},{ref:"Luke 9:42",text:"Jesus rebuked the impure spirit, healed the boy and gave him back to his father."}], related:["healing","mental-health","strength","children","faith"] },

  { slug:"asthma", title:"Prayer for Asthma", metaDesc:"A prayer for healing from asthma — for free breathing, clear airways, and God's breath of life.", category:"Health", keywords:["prayer for asthma","asthma healing prayer","prayer for breathing","prayer for respiratory disease"], samplePrayer:"Lord, You breathed life into humanity at creation — breathe healing into these airways now. Let every constriction loosen. Let lungs expand freely. Remove every trigger, every inflammation, every attack. You are the God who breathed, and these lungs were made to breathe fully. I receive clear airways in Jesus' name, Amen.", scripture:[{ref:"Genesis 2:7",text:"The Lord God breathed into his nostrils the breath of life."},{ref:"Ezekiel 37:5",text:"I will make breath enter you, and you will come to life."}], related:["healing","children","recovery","hospital","strength"] },

  { slug:"postpartum-depression", title:"Prayer for Postpartum Depression", metaDesc:"A prayer for mothers suffering postpartum depression after birth — for healing, joy, bonding, and God's strength.", category:"Mental Health", keywords:["prayer for postpartum depression","postpartum prayer","prayer after baby","new mom prayer"], samplePrayer:"Father, giving birth is one of the most monumental events in life — but when joy is replaced by darkness, I bring this mother to You. Postpartum depression is real and it is heavy. Lift this weight. Restore connection with this beautiful baby. Let help come — professional, relational, spiritual. Remind her she is not failing — she is fighting. And You are fighting with her. In Jesus' name, Amen.", scripture:[{ref:"Psalm 34:18",text:"The Lord is close to the brokenhearted."},{ref:"Isaiah 66:13",text:"As a mother comforts her child, so will I comfort you."}], related:["newborn-baby","pregnancy","mental-health","depression","mothers"] },

  { slug:"panic-attacks", title:"Prayer for Panic Attacks", metaDesc:"A prayer to stop panic attacks — for peace, calm breath, and God's power to still the storm of the mind.", category:"Mental Health", keywords:["prayer for panic attacks","panic attack prayer","prayer during panic attack","prayer for panic disorder"], samplePrayer:"Right now, in this moment of panic — Lord, I need You. My heart is racing, my thoughts are spiraling, my body is responding to a fear that isn't real. Speak peace. Slow my breathing. Remind me I am safe. You have not given me a spirit of fear. I command this panic to cease in Jesus' name. Still my body. Still my mind. You are here. I am not alone. Amen.", scripture:[{ref:"2 Timothy 1:7",text:"God gave us a spirit not of fear but of power."},{ref:"Isaiah 41:10",text:"Do not be afraid; I am with you."}], related:["anxiety","fear","stress","mental-health","peace"] },

  { slug:"ocd", title:"Prayer for OCD", metaDesc:"A prayer for healing from OCD and intrusive thoughts — for a sound, free, and peaceful mind in Christ.", category:"Mental Health", keywords:["prayer for OCD","obsessive compulsive disorder prayer","intrusive thoughts prayer","prayer for pure OCD"], samplePrayer:"Lord, the mind is a battlefield and OCD wages war through intrusive thoughts and compulsive cycles. I bring this battle to You. You said to take every thought captive to Christ — help me do that. Break the cycle. Renew my mind. Let me see that these thoughts do not define me. You have given me a sound mind and I receive it now. In Jesus' name, Amen.", scripture:[{ref:"2 Corinthians 10:5",text:"We take captive every thought to make it obedient to Christ."},{ref:"Romans 12:2",text:"Be transformed by the renewing of your mind."}], related:["anxiety","mental-health","fear","peace","healing"] },

  { slug:"bipolar", title:"Prayer for Bipolar Disorder", metaDesc:"A prayer for those living with bipolar disorder — for stability, clarity, the right treatment, and God's peace through every season.", category:"Mental Health", keywords:["prayer for bipolar","bipolar disorder prayer","prayer for mood disorder","prayer for manic episode"], samplePrayer:"Father, the swings between highs and lows are exhausting. Stability feels like a distant dream. But You are the same yesterday, today, and forever — and I pray that Your steadiness would anchor this mind. Guide toward the right medication, the right therapist, the right support. In mania or depression, let Your voice be the loudest. In Jesus' name, Amen.", scripture:[{ref:"Hebrews 13:8",text:"Jesus Christ is the same yesterday and today and forever."},{ref:"Psalm 46:10",text:"Be still, and know that I am God."}], related:["mental-health","depression","anxiety","stability","strength"] },

  { slug:"eating-disorder", title:"Prayer for Eating Disorders", metaDesc:"A prayer for healing from anorexia, bulimia, or binge eating — for a healthy relationship with food and body image.", category:"Mental Health", keywords:["prayer for eating disorder","anorexia prayer","bulimia prayer","prayer for body image","prayer for binge eating"], samplePrayer:"Lord, You said we are fearfully and wonderfully made — but lies about this body have taken root. Uproot them. Replace every distortion with truth. Let food become nourishment again, not enemy. Let the mirror reflect what You see, not what the disease says. Restore a healthy relationship with eating. In Jesus' name, Amen.", scripture:[{ref:"Psalm 139:14",text:"I am fearfully and wonderfully made."},{ref:"1 Corinthians 6:19",text:"Your bodies are temples of the Holy Spirit."}], related:["mental-health","healing","body-image","depression","anxiety"] },

  { slug:"suicidal-thoughts", title:"Prayer for Suicidal Thoughts", metaDesc:"A prayer for anyone battling suicidal thoughts — God sees your pain, your life has infinite value, and help is here.", category:"Mental Health", keywords:["prayer for suicidal thoughts","suicidal prayer","prayer for wanting to die","prayer for depression and suicide"], samplePrayer:"God, if someone is reading this and the pain has become unbearable — I pray they feel Your presence right now. You formed them with purpose. Their life is not a mistake. The darkness is lying. Reach into this darkness and touch this heart. Send someone. Open a door. Let them make the call, reach out, hold on one more moment. You are not done with them. In Jesus' name, Amen.", scripture:[{ref:"John 10:10",text:"I have come that they may have life, and have it to the full."},{ref:"Jeremiah 29:11",text:"For I know the plans I have for you, plans to prosper you."}], related:["depression","mental-health","hope","comfort","anxiety"] },

  { slug:"self-harm", title:"Prayer for Self-Harm", metaDesc:"A prayer for freedom from self-harm — God's love is the healing that wounds cannot reach, and He offers it freely.", category:"Mental Health", keywords:["prayer for self harm","self-harm prayer","prayer for cutting","prayer for self injury"], samplePrayer:"Father, pain that has no words sometimes finds expression in ways that hurt this body. I pray for anyone in that place — that they would find in You what they are searching for in the blade: relief, control, proof they exist. You see the pain behind the action. Heal the wound beneath the wound. Let love reach where nothing else has. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 61:1",text:"He has sent me to bind up the brokenhearted."},{ref:"Psalm 147:3",text:"He heals the brokenhearted and binds up their wounds."}], related:["mental-health","depression","healing","hope","trauma"] },

  { slug:"addiction-to-pornography", title:"Prayer for Pornography Addiction", metaDesc:"A prayer for freedom from pornography addiction — for purity, accountability, and the restoration of a healthy mind.", category:"Mental Health", keywords:["prayer for pornography addiction","porn addiction prayer","prayer for sexual purity","prayer to stop watching pornography"], samplePrayer:"Lord Jesus, this addiction has robbed me of purity, relationships, and peace of mind. I come to You broken and honest. Destroy every stronghold. Rewire what has been corrupted. Bring accountability partners, software filters, and Your Holy Spirit as the ultimate guard. Let purity feel possible — because with You, it is. In Jesus' name, Amen.", scripture:[{ref:"1 Corinthians 6:18",text:"Flee from sexual immorality."},{ref:"Psalm 51:10",text:"Create in me a pure heart, O God."}], related:["addiction","sexual-purity","deliverance","forgiveness","strength"] },

  // ── MARRIAGE & ROMANCE ────────────────────────────────────────────────

  { slug:"marriage-restoration", title:"Prayer for Marriage Restoration", metaDesc:"A prayer to restore a broken marriage — for healing after betrayal, separation, or near-divorce.", category:"Relationships", keywords:["prayer for marriage restoration","prayer to save my marriage","prayer for broken marriage","marriage reconciliation prayer"], samplePrayer:"God, You invented marriage and You can repair what feels beyond repair. I pray for this marriage. What the enemy has tried to destroy, I ask You to restore. Soften hearts. Remove bitterness. Rebuild trust brick by brick. Let both partners choose love again, even when it is hard. What You have joined, let no one separate. In Jesus' name, Amen.", scripture:[{ref:"Matthew 19:6",text:"What God has joined together, let no one separate."},{ref:"Joel 2:25",text:"I will repay you for the years the locusts have eaten."}], related:["marriage","husband","wife","forgiveness","reconciliation"] },

  { slug:"cheating-spouse", title:"Prayer After a Cheating Spouse", metaDesc:"A prayer for healing after infidelity — for the betrayed and the one who strayed, for restoration or healing to move forward.", category:"Relationships", keywords:["prayer for cheating spouse","infidelity prayer","prayer after affair","prayer for unfaithful husband","prayer for unfaithful wife"], samplePrayer:"Lord, infidelity tears at the soul. The betrayal runs deep and the pain is real. I bring this broken situation to You. For the one betrayed — heal the wound, restore dignity, and guide forward wisely. For the one who strayed — bring genuine repentance and a changed heart. Whether this marriage is restored or not, let healing begin today. In Jesus' name, Amen.", scripture:[{ref:"Psalm 147:3",text:"He heals the brokenhearted and binds up their wounds."},{ref:"Hosea 2:15",text:"I will make the Valley of Trouble a door of hope."}], related:["marriage","forgiveness","healing","marriage-restoration","trust"] },

  { slug:"prayer-for-future-spouse", title:"Prayer for Future Spouse", metaDesc:"A prayer for your future husband or wife — trusting God to prepare you both and bring you together in His perfect timing.", category:"Relationships", keywords:["prayer for future spouse","prayer for husband","prayer for future wife","prayer for marriage partner","prayer while waiting for love"], samplePrayer:"Lord, wherever my future spouse is right now — protect them. Prepare them. Draw them closer to You. And prepare me to be the partner they need. Let our meeting be ordered by You, not by desperation. Give me patience in this waiting season and faith that Your timing is perfect. When we meet, let it be unmistakably Your doing. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 18:22",text:"He who finds a wife finds what is good."},{ref:"Psalm 37:4",text:"Take delight in the Lord, and he will give you the desires of your heart."}], related:["love","single-parent","patience","waiting-on-god","marriage"] },

  { slug:"toxic-relationship", title:"Prayer to Leave a Toxic Relationship", metaDesc:"A prayer for strength to leave a toxic or abusive relationship and walk in the freedom and dignity God designed for you.", category:"Relationships", keywords:["prayer to leave toxic relationship","prayer for abusive relationship","prayer for strength to leave","toxic relationship prayer"], samplePrayer:"Lord, I was not created for this. You designed relationships to be safe, loving, and life-giving — not to diminish, control, or harm. Give me the courage to leave what is destroying me. Remove the fear, the dependency, the false hope. Open a door of escape and guard me as I walk through it. My worth is not defined by how this person treats me. In Jesus' name, Amen.", scripture:[{ref:"1 Corinthians 10:13",text:"God will provide a way out so that you can endure it."},{ref:"Psalm 34:18",text:"The Lord is close to the brokenhearted."}], related:["domestic-violence","healing","courage","forgiveness","protection"] },

  { slug:"domestic-violence", title:"Prayer for Domestic Violence Victims", metaDesc:"A prayer for those suffering domestic abuse — for safety, protection, courage to seek help, and God's restoration.", category:"Relationships", keywords:["prayer for domestic violence","abuse prayer","prayer for battered woman","prayer for abuse survivor","prayer for safety from abuser"], samplePrayer:"God of justice, I cry out for every person trapped in abuse right now. You see what happens behind closed doors. I pray for safety — supernatural protection tonight. Raise up a way of escape. Give courage to make the call, to leave, to tell the truth. And bring healing to deep wounds that violence leaves behind. You are the defender of the vulnerable. In Jesus' name, Amen.", scripture:[{ref:"Psalm 82:3",text:"Defend the weak and the fatherless."},{ref:"Nahum 1:7",text:"The Lord is good, a refuge in times of trouble."}], related:["protection","healing","courage","safety","trauma"] },

  { slug:"prayer-for-son", title:"Prayer for My Son", metaDesc:"A powerful prayer for your son — for his protection, faith, purpose, health, and God's mighty hand on his life.", category:"Family", keywords:["prayer for my son","prayer for son","mother's prayer for son","father's prayer for son"], samplePrayer:"Father, I lift my son to You today. You know him better than I do. Protect him from every danger seen and unseen. Keep him from wrong paths and wrong friends. Plant Your Word deep in his heart. May he grow into a man of God — courageous, faithful, kind, and purpose-driven. I cover him in prayer every day of his life. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 22:6",text:"Start children off on the way they should go."},{ref:"3 John 1:4",text:"I have no greater joy than to hear that my children are walking in the truth."}], related:["children","family","protection","faith","mothers"] },

  { slug:"prayer-for-daughter", title:"Prayer for My Daughter", metaDesc:"A prayer for your daughter — for her protection, identity in Christ, future, and God's love to define her worth.", category:"Family", keywords:["prayer for my daughter","prayer for daughter","mothers prayer for daughter","fathers prayer for daughter"], samplePrayer:"Lord, I pray for this daughter who is a gift beyond measure. Protect her heart from those who would exploit it. Build her identity on who You say she is — not what the world tells her. Keep her from destructive paths and draw her to Your purposes. Let her know she is loved, valued, and chosen. In Jesus' name, Amen.", scripture:[{ref:"Psalm 45:13",text:"The king's daughter is all glorious within."},{ref:"Isaiah 49:15",text:"I will not forget you."}], related:["children","family","protection","faith","daughters"] },

  { slug:"mothers", title:"Prayer for Mothers", metaDesc:"A prayer for all mothers — for strength, wisdom, patience, and God's grace to cover everything they carry.", category:"Family", keywords:["prayer for mothers","mothers prayer","prayer for mom","prayer for single mother","mothers day prayer"], samplePrayer:"Lord, motherhood is one of the most demanding and sacred callings on earth. I pray for every mother today — the tired ones, the grieving ones, the single ones, the ones who doubt themselves. Replenish what has been poured out. Let them feel seen and appreciated. Their sacrifice is a form of worship. Bless them, strengthen them, and remind them they are doing better than they think. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 31:25",text:"She is clothed with strength and dignity."},{ref:"Isaiah 66:13",text:"As a mother comforts her child, so will I comfort you."}], related:["family","children","single-parent","strength","gratitude"] },

  { slug:"fathers", title:"Prayer for Fathers", metaDesc:"A prayer for fathers — for wisdom to lead, strength to protect, and grace to be the fathers their children need.", category:"Family", keywords:["prayer for fathers","fathers prayer","prayer for dad","prayer for fatherhood","fathers day prayer"], samplePrayer:"Heavenly Father, You are the perfect model of fatherhood. Raise up every father to reflect Your character — patient, strong, present, and loving. For absent fathers — bring restoration. For struggling fathers — give grace. For new fathers — give wisdom. Let the next generation rise because of the prayers and sacrifices of godly fathers. In Jesus' name, Amen.", scripture:[{ref:"Psalm 103:13",text:"As a father has compassion on his children, so the Lord has compassion."},{ref:"Malachi 4:6",text:"He will turn the hearts of the parents to their children."}], related:["family","children","marriage","husband","strength"] },

  { slug:"stepchildren", title:"Prayer for Stepchildren and Blended Families", metaDesc:"A prayer for blended families — for unity, love between stepchildren and stepparents, and God's grace in complex family dynamics.", category:"Family", keywords:["prayer for stepchildren","blended family prayer","prayer for stepparent","prayer for step family"], samplePrayer:"Lord, blended families are complex, and only Your love can truly hold them together. I pray for every stepchild navigating divided loyalties and every stepparent trying to love children who may resist it. Knit these hearts together. Replace rejection with belonging. Replace competition with cooperation. Let this family become a testimony of Your redemptive grace. In Jesus' name, Amen.", scripture:[{ref:"Romans 15:7",text:"Accept one another, just as Christ accepted you."},{ref:"Psalm 68:6",text:"God sets the lonely in families."}], related:["family","divorce","children","marriage","love"] },

  { slug:"adopted-children", title:"Prayer for Adopted Children", metaDesc:"A prayer for adopted children and adoptive families — celebrating God's design of adoption and the beauty of chosen family.", category:"Family", keywords:["prayer for adopted child","adoption prayer","prayer for adoptive parents","prayer before adoption"], samplePrayer:"Father, adoption is Your idea — You adopted us into Your family through Jesus. I pray for every adopted child: may they never doubt they were chosen with intention and loved completely. For adoptive parents — give wisdom, patience, and supernatural love. Heal every wound of abandonment and let belonging take root deeply. In Jesus' name, Amen.", scripture:[{ref:"Ephesians 1:5",text:"He predestined us for adoption to sonship through Jesus Christ."},{ref:"Romans 8:15",text:"The Spirit you received brought about your adoption."}], related:["children","family","healing","love","foster-care"] },

  { slug:"foster-care", title:"Prayer for Children in Foster Care", metaDesc:"A prayer for children in the foster care system — for safety, love, permanence, and God's protective hand.", category:"Family", keywords:["prayer for foster children","foster care prayer","prayer for foster parents","prayer for orphans"], samplePrayer:"God, You are the Father to the fatherless. I pray for every child in foster care tonight — in an unfamiliar bed, in an unfamiliar home, carrying wounds no child should carry. Protect them. Assign them the right foster family. Bring permanence. And raise up more families willing to open their homes. You see every one of these children. In Jesus' name, Amen.", scripture:[{ref:"Psalm 68:5",text:"A father to the fatherless, a defender of widows, is God."},{ref:"James 1:27",text:"Religion that God our Father accepts: to look after orphans and widows."}], related:["children","family","adoption","protection","love"] },

  { slug:"wayward-child", title:"Prayer for a Wayward Child", metaDesc:"A prayer for a son or daughter who has walked away from God — trust that the Father of the prodigal son is still waiting.", category:"Family", keywords:["prayer for wayward child","prayer for rebellious child","prayer for child who left church","prayer for prodigal child"], samplePrayer:"Father of the prodigal, I pray for my child who has walked away. You never stopped watching for the prodigal son's return, and I ask You to do the same for mine. Frustrate every wrong path. Let every substitute for You fall short. Bring them home — to You first, then to us. I will not stop praying until they return. In Jesus' name, Amen.", scripture:[{ref:"Luke 15:20",text:"But while he was still a long way off, his father saw him."},{ref:"Jeremiah 31:16",text:"Your children will return from the land of the enemy."}], related:["prodigal-son","children","family","salvation","hope"] },

  { slug:"in-laws", title:"Prayer for Difficult In-Laws", metaDesc:"A prayer for peace and wisdom when dealing with difficult in-laws — for boundaries, love, and God's grace in family tension.", category:"Family", keywords:["prayer for in-laws","in-law prayer","prayer for mother-in-law","prayer for difficult family member"], samplePrayer:"Lord, in-law relationships can be one of the most challenging dynamics in family life. Give me love that is not conditional on being loved well in return. Help me set healthy boundaries with grace. Let peace govern our interactions. And where restoration is possible, make it happen. Protect my marriage from family friction and let unity be stronger than the tension. In Jesus' name, Amen.", scripture:[{ref:"Romans 12:18",text:"If it is possible, as far as it depends on you, live at peace with everyone."},{ref:"Proverbs 15:1",text:"A gentle answer turns away wrath."}], related:["family","marriage","forgiveness","boundaries","peace"] },

  // ── PREGNANCY & BIRTH ────────────────────────────────────────────────

  { slug:"fertility-prayer", title:"Prayer for Fertility", metaDesc:"A faith-filled prayer for fertility and conception — trusting God to open the womb and bring forth new life.", category:"Family", keywords:["prayer for fertility","fertility prayer","prayer to get pregnant","prayer for conception","prayer for a baby"], samplePrayer:"Lord, You are the Giver of life. You opened Sarah's womb, Hannah's womb, Elizabeth's womb — and I believe You can open mine. I pray against every medical obstacle. Let conception happen. Let this body do what You designed it to do. And while I wait, let hope not die. You are the God who gives life — I trust You with this deepest desire. In Jesus' name, Amen.", scripture:[{ref:"Psalm 113:9",text:"He settles the childless woman in her home as a happy mother of children."},{ref:"Genesis 21:2",text:"Sarah became pregnant and bore a son to Abraham."}], related:["infertility","pregnancy","miscarriage","hope","waiting-on-god"] },

  { slug:"healthy-pregnancy", title:"Prayer for a Healthy Pregnancy", metaDesc:"A prayer for a safe and healthy pregnancy — for mother and baby, from conception to delivery.", category:"Family", keywords:["prayer for healthy pregnancy","pregnancy prayer","prayer for baby in womb","prayer during pregnancy"], samplePrayer:"Lord, I carry this child and I carry this prayer — that every day of this pregnancy would be covered by Your hand. Protect this baby from every complication. Nourish, grow, and develop every organ, every system perfectly. Guard the mother's body and mind. Let checkups bring good news and let this pregnancy lead to a safe and joyful delivery. In Jesus' name, Amen.", scripture:[{ref:"Psalm 139:13",text:"You knit me together in my mother's womb."},{ref:"Isaiah 46:3",text:"I have upheld you since your birth."}], related:["pregnancy","fertility-prayer","newborn-baby","mothers","faith"] },

  { slug:"safe-delivery", title:"Prayer for Safe Labor and Delivery", metaDesc:"A prayer for safe, peaceful labor and delivery — for mother, baby, and every medical professional in the room.", category:"Family", keywords:["prayer for safe delivery","labor prayer","childbirth prayer","prayer before giving birth"], samplePrayer:"Lord, this is the moment of delivery — one of the most powerful moments in human experience. I pray for a safe birth. Guide the doctors and midwives. Let the baby arrive at the right time, in the right position, with healthy lungs and a strong cry. Protect the mother through every contraction. Let the room be filled with Your peace and let joy erupt at the sound of new life. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 66:9",text:"Do I bring to the moment of birth and not give delivery? says the Lord."},{ref:"John 16:21",text:"A woman giving birth to a child has pain — but when her baby is born she forgets the anguish."}], related:["pregnancy","newborn-baby","healthy-pregnancy","hospital","mothers"] },

  { slug:"stillbirth", title:"Prayer After a Stillbirth", metaDesc:"A prayer for parents who have experienced the devastating loss of a stillbirth — for comfort, healing, and God's presence in unimaginable grief.", category:"Grief", keywords:["prayer for stillbirth","stillbirth prayer","prayer for baby loss","prayer for bereaved parents"], samplePrayer:"God, there are no words. A baby born silent is a grief the world rarely acknowledges fully. But You do. You held this child before they were born. You hold these parents now. Comfort what words cannot comfort. Let Your presence be more real than the emptiness. Let healing come slowly and completely. And may these parents know their child is safe in Your arms. In Jesus' name, Amen.", scripture:[{ref:"Matthew 5:4",text:"Blessed are those who mourn, for they will be comforted."},{ref:"Revelation 21:4",text:"He will wipe every tear from their eyes."}], related:["miscarriage","grief","comfort","healing","hope"] },

  { slug:"nicu-prayer", title:"Prayer for Baby in the NICU", metaDesc:"A prayer for a premature or sick baby in the NICU — for miraculous growth, healing, and God's protective hand.", category:"Health", keywords:["prayer for NICU baby","premature baby prayer","prayer for preemie","NICU prayer"], samplePrayer:"Lord, this tiny baby is fighting with a strength that defies their size. I pray for every baby in the NICU right now. Develop every lung, every organ, every system. Let weight increase, let numbers improve, let nurses see miracles they cannot explain. Comfort the parents enduring the hardest wait of their lives. This baby is covered by Your hand. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 46:4",text:"Even to your old age and gray hairs I am he who will sustain you."},{ref:"Psalm 22:10",text:"From birth I was cast on you; from my mother's womb you have been my God."}], related:["newborn-baby","pregnancy","hospital","healing","faith"] },

  // ── WORK & CAREER ───────────────────────────────────────────────────

  { slug:"job-loss", title:"Prayer After Losing a Job", metaDesc:"A prayer after job loss — for peace, provision, direction, and God's open doors after unexpected unemployment.", category:"Finance", keywords:["prayer for job loss","prayer after being fired","unemployment prayer","prayer for redundancy","losing job prayer"], samplePrayer:"Father, this job loss feels like the ground has shifted. Fear wants to take over. But I choose to trust that You saw this coming even when I didn't — and You already have a plan. Provide for my needs during this season. Open the right doors. Give me clarity, confidence, and divine connections. This is not the end of my story. In Jesus' name, Amen.", scripture:[{ref:"Philippians 4:19",text:"God will meet all your needs according to the riches of his glory."},{ref:"Jeremiah 29:11",text:"I know the plans I have for you, plans to prosper you."}], related:["job","work","provision","faith","breakthrough"] },

  { slug:"toxic-workplace", title:"Prayer for a Toxic Workplace", metaDesc:"A prayer for endurance, wisdom, and protection in a toxic work environment — or guidance on when to leave.", category:"Finance", keywords:["prayer for toxic workplace","workplace prayer","prayer for difficult boss","prayer for work stress","prayer against workplace bullying"], samplePrayer:"Lord, I spend most of my waking hours in this workplace and it is draining the life from me. I pray for Your wisdom — whether to endure, to confront, or to leave. Protect me from unfair treatment. Give me grace to handle difficult colleagues without losing my integrity. And if it is time to go, open that door quickly. In Jesus' name, Amen.", scripture:[{ref:"Colossians 3:23",text:"Whatever you do, work at it with all your heart, as working for the Lord."},{ref:"Romans 12:19",text:"Do not take revenge, my dear friends, but leave room for God's wrath."}], related:["work","job","stress","courage","guidance"] },

  { slug:"business-breakthrough", title:"Prayer for Business Breakthrough", metaDesc:"A prayer for a business breakthrough — for new clients, revenue, ideas, and God's favor to open supernatural doors.", category:"Finance", keywords:["prayer for business breakthrough","business prayer","prayer for my business","entrepreneur prayer","prayer for business growth"], samplePrayer:"Lord, I have built this business and I need Your blessing on it. Let new clients find their way to my door. Let ideas flow. Let contracts be signed. Give me wisdom in every decision and favor in every meeting. What hands cannot achieve, let Your supernatural influence accomplish. This business is dedicated to Your glory — bless it beyond what I can ask or imagine. In Jesus' name, Amen.", scripture:[{ref:"Deuteronomy 8:18",text:"Remember the Lord your God, for it is he who gives you the ability to produce wealth."},{ref:"Proverbs 16:3",text:"Commit to the Lord whatever you do, and he will establish your plans."}], related:["business","financial-breakthrough","favor","work","provision"] },

  { slug:"career-change", title:"Prayer for Career Change", metaDesc:"A prayer for wisdom and confidence during a career change — for God to direct your steps into the right purpose.", category:"Finance", keywords:["prayer for career change","career prayer","prayer for new career","prayer for career direction","prayer to change jobs"], samplePrayer:"Lord, something in my spirit knows this chapter is ending and a new one is beginning. But the transition is scary. What if I choose wrong? I trust that You order my steps. Give me discernment to identify the right path. Give me courage to take the leap. And let my next career chapter be the most fruitful one yet — not just financially, but with purpose. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 3:5-6",text:"Trust in the Lord with all your heart and lean not on your own understanding."},{ref:"Isaiah 30:21",text:"Whether you turn to the right or to the left, your ears will hear a voice saying, 'This is the way.'"}], related:["guidance","work","purpose","calling","faith"] },

  { slug:"entrepreneurship", title:"Prayer for Entrepreneurs", metaDesc:"A prayer for entrepreneurs starting and building businesses — for vision, resilience, wisdom, and God's open doors.", category:"Finance", keywords:["prayer for entrepreneurs","startup prayer","small business prayer","prayer for business owner","prayer for self-employed"], samplePrayer:"God of creativity and increase, I bring this entrepreneurial vision before You. You gave me this idea — now help me build it. Provide the capital, the team, the clients, the strategy. Protect me from discouragement in the early stages. Let the resilience of purpose outweigh the fear of failure. And let this business serve people well as an act of worship. In Jesus' name, Amen.", scripture:[{ref:"Genesis 2:15",text:"The Lord God took the man and put him in the Garden of Eden to work it."},{ref:"Ecclesiastes 5:12",text:"The sleep of a laborer is sweet."}], related:["business","business-breakthrough","work","provision","purpose"] },

  { slug:"work-life-balance", title:"Prayer for Work-Life Balance", metaDesc:"A prayer for healthy boundaries between work and rest — for productivity, presence at home, and Sabbath rest.", category:"Finance", keywords:["prayer for work-life balance","overwork prayer","prayer for rest from work","prayer against workaholism"], samplePrayer:"Lord, You worked six days and rested on the seventh — and You designed me to do the same. I confess I have let work swallow my life. Restore the balance. Help me be fully present at home when I am home and fully focused at work when I am working. Let rest not feel like weakness. Let boundaries not feel like failure. Teach me the rhythm of Your Sabbath rest. In Jesus' name, Amen.", scripture:[{ref:"Exodus 20:8",text:"Remember the Sabbath day by keeping it holy."},{ref:"Matthew 11:28",text:"Come to me, all you who are weary and burdened, and I will give you rest."}], related:["work","rest","burnout","family","peace"] },

  // ── FINANCES ────────────────────────────────────────────────────────

  { slug:"debt-freedom", title:"Prayer for Freedom from Debt", metaDesc:"A prayer for debt freedom — for financial wisdom, breakthrough, and God's supernatural provision to pay every creditor.", category:"Finance", keywords:["prayer for debt","prayer for freedom from debt","debt prayer","prayer to pay off debt","prayer for credit card debt"], samplePrayer:"Father, this debt feels like a yoke around my neck. I bring every creditor, every balance, every statement to You. Give me a supernatural debt-elimination plan. Open income streams I have not seen. Give me discipline to spend wisely. And let me experience the freedom of owing no man anything but love. In Jesus' name, Amen.", scripture:[{ref:"Romans 13:8",text:"Let no debt remain outstanding, except the continuing debt to love one another."},{ref:"Proverbs 22:7",text:"The borrower is slave to the lender."}], related:["debt","financial-breakthrough","provision","wisdom","breakthrough"] },

  { slug:"mortgage-prayer", title:"Prayer for a House and Mortgage", metaDesc:"A prayer for a home — for approval, provision, and God's favor in finding and purchasing the right house.", category:"Finance", keywords:["prayer for a house","mortgage prayer","prayer to buy a home","prayer for house approval","prayer for first home"], samplePrayer:"Lord, the desire for a home — a place of safety, stability, and belonging — is a desire You placed in us. I pray for this mortgage to be approved, this house to be the right one, and this purchase to go through without hindrance. What banks see as a risk, let Your favor make possible. Give me a home that becomes a sanctuary. In Jesus' name, Amen.", scripture:[{ref:"Psalm 127:1",text:"Unless the Lord builds the house, the builders labor in vain."},{ref:"Proverbs 24:3",text:"By wisdom a house is built, and through understanding it is established."}], related:["financial-breakthrough","provision","favor","moving","blessing"] },

  { slug:"tithing", title:"Prayer for Tithing and Generosity", metaDesc:"A prayer for the grace to tithe faithfully and give generously — trusting God to open the windows of heaven.", category:"Finance", keywords:["prayer for tithing","tithing prayer","prayer for generosity","prayer before giving","prayer for offerings"], samplePrayer:"Lord, I open my hand and release this tithe as an act of faith and worship. I believe Your Word — that the windows of heaven will open and overflow. Rebuke the devourer. Let every seed I sow multiply. And cultivate in me a generous heart that gives not from obligation but from overflow and joy. In Jesus' name, Amen.", scripture:[{ref:"Malachi 3:10",text:"Bring the whole tithe into the storehouse... Test me in this, says the Lord Almighty."},{ref:"2 Corinthians 9:7",text:"God loves a cheerful giver."}], related:["financial-breakthrough","blessing","gratitude","provision","worship"] },

  { slug:"prayer-for-abundance", title:"Prayer for Abundance and Prosperity", metaDesc:"A scriptural prayer for abundance and prosperity — trusting God to bless the work of your hands and overflow your cup.", category:"Finance", keywords:["prayer for abundance","prosperity prayer","prayer for wealth","prayer for overflow","prayer for increase"], samplePrayer:"Lord, You said You came to give life and give it abundantly. I receive that abundance today — not just spiritual, but material. Bless the work of my hands. Let increase come from unexpected directions. Let my cup overflow so I can pour into others. I do not pray for selfish gain but for the resources to fulfill my purpose and bless those around me. In Jesus' name, Amen.", scripture:[{ref:"John 10:10",text:"I have come that they may have life, and have it to the full."},{ref:"Psalm 23:5",text:"My cup overflows."}], related:["financial-breakthrough","blessing","provision","business-breakthrough","tithing"] },

  // ── SPIRITUAL LIFE ───────────────────────────────────────────────────

  { slug:"spiritual-dryness", title:"Prayer for Spiritual Dryness", metaDesc:"A prayer for those experiencing a spiritual desert season — when God feels distant and prayer feels empty.", category:"Faith", keywords:["prayer for spiritual dryness","dry season prayer","prayer when God feels distant","prayer for spiritual renewal"], samplePrayer:"Lord, I am in a dry place. My prayers feel like they bounce off the ceiling. I can't feel Your presence like I used to. But I refuse to trust feelings over truth. Your Word says You will never leave me. So I choose to press in even when the fire is low. Revive me. Send rain to this dry ground. Let worship return. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 44:3",text:"I will pour water on the thirsty land, and streams on the dry ground."},{ref:"Psalm 63:1",text:"You, God, are my God, earnestly I seek you; I thirst for you."}], related:["faith","spiritual-growth","worship","doubt","breakthrough"] },

  { slug:"doubt", title:"Prayer for Doubt and Unbelief", metaDesc:"A prayer for those struggling with doubt — asking God to meet you in your honest questions and renew your faith.", category:"Faith", keywords:["prayer for doubt","prayer for unbelief","prayer when doubting God","prayer for weak faith"], samplePrayer:"Lord, I believe — help my unbelief. Like the man who came to Jesus with a struggling faith, I come the same way. I will not pretend certainty I do not have. But I bring my doubts to You instead of walking away. Meet me here. Let evidence of Your reality stack up. Let my questions lead me toward You rather than away. In Jesus' name, Amen.", scripture:[{ref:"Mark 9:24",text:"I do believe; help me overcome my unbelief!"},{ref:"John 20:27",text:"Stop doubting and believe."}], related:["faith","spiritual-growth","hope","trust","spiritual-dryness"] },

  { slug:"hearing-god", title:"Prayer to Hear God's Voice", metaDesc:"A prayer for sensitivity to God's voice — to hear clearly in prayer, Scripture, and everyday life.", category:"Faith", keywords:["prayer to hear God","prayer for hearing God's voice","prayer for discernment","prayer to know God's will"], samplePrayer:"Speak, Lord — Your servant is listening. I quiet the noise of this world to tune into Your voice. Train my spiritual ears to recognize when You speak. Whether through Your Word, a prompting, a dream, or a still small voice — let me hear You clearly. Let me not miss the whisper in the crowd. In Jesus' name, Amen.", scripture:[{ref:"1 Samuel 3:10",text:"Speak, Lord, for your servant is listening."},{ref:"John 10:27",text:"My sheep listen to my voice; I know them, and they follow me."}], related:["guidance","wisdom","spiritual-growth","direction","calling"] },

  { slug:"sexual-purity", title:"Prayer for Sexual Purity", metaDesc:"A prayer for sexual purity — for strength against temptation, healing from sexual sin, and a renewed commitment to holiness.", category:"Faith", keywords:["prayer for sexual purity","purity prayer","prayer against sexual temptation","prayer for holiness","prayer for celibacy"], samplePrayer:"Lord, purity is not popular in today's culture but it is still Your design. I bring my struggles to You honestly. Where I have fallen, restore me. Where temptation is strong, be stronger. Let my body be a temple of Your Holy Spirit. Give me accountability, spiritual discipline, and a greater love for holiness than for momentary pleasure. In Jesus' name, Amen.", scripture:[{ref:"1 Corinthians 6:18-19",text:"Flee from sexual immorality... your bodies are temples of the Holy Spirit."},{ref:"1 Thessalonians 4:3",text:"It is God's will that you should be sanctified: that you should avoid sexual immorality."}], related:["addiction-to-pornography","forgiveness","strength","deliverance","spiritual-growth"] },

  { slug:"church-hurt", title:"Prayer After Being Hurt by Church", metaDesc:"A prayer for healing after being wounded by a church, pastor, or religious community — God is bigger than their mistakes.", category:"Faith", keywords:["prayer for church hurt","church trauma prayer","prayer after leaving church","religious trauma prayer","prayer for betrayal by pastor"], samplePrayer:"Lord, I came to church looking for You and found pain instead. The betrayal of spiritual leaders runs deep. Help me separate You from the people who failed me. You never hurt me — they did. Heal this wound. Restore my love for Your body. Bring me to a safe, healthy community. And let me not punish You for what humans did. In Jesus' name, Amen.", scripture:[{ref:"Psalm 118:8",text:"It is better to take refuge in the Lord than to trust in humans."},{ref:"Hebrews 10:25",text:"Not giving up meeting together, as some are in the habit of doing."}], related:["healing","forgiveness","faith","comfort","spiritual-growth"] },

  { slug:"generational-curses", title:"Prayer to Break Generational Curses", metaDesc:"A prayer to break generational curses — patterns of sin, poverty, disease, or dysfunction passed down through family lines.", category:"Faith", keywords:["prayer to break generational curses","generational curse prayer","prayer for family curse","prayer for breaking family patterns"], samplePrayer:"In the name of Jesus Christ, I stand at the crossroads of my family line and declare: the curse stops here. Every pattern of addiction, poverty, abuse, disease, or dysfunction that has followed my family — I renounce and break it now. The blood of Jesus speaks better things over me and my descendants. A new legacy begins with this generation. In Jesus' name, Amen.", scripture:[{ref:"Galatians 3:13",text:"Christ redeemed us from the curse of the law."},{ref:"Ezekiel 18:20",text:"The son will not share the guilt of the father."}], related:["deliverance","spiritual-warfare","protection-from-enemies","family","breakthrough"] },

  { slug:"prayer-for-dreams", title:"Prayer for Godly Dreams and Visions", metaDesc:"A prayer to receive dreams and visions from God — and for discernment to understand what He is saying.", category:"Faith", keywords:["prayer for dreams from God","prayer for visions","prayer for divine dreams","prayer to understand dreams"], samplePrayer:"Lord, You spoke to Joseph, to Daniel, to the prophets — through dreams. You said in the last days Your people would dream dreams and see visions. Open that channel for me. Let my sleep be sacred communion. Give me dreams that instruct, warn, encourage, and reveal. And give me the discernment to know what is from You. In Jesus' name, Amen.", scripture:[{ref:"Joel 2:28",text:"Your sons and daughters will prophesy, your old men will dream dreams."},{ref:"Job 33:14-15",text:"In a dream, in a vision of the night... he speaks."}], related:["hearing-god","spiritual-growth","faith","purpose","wisdom"] },

  { slug:"prayer-for-revival", title:"Prayer for Personal Revival", metaDesc:"A prayer for personal revival — for the fire of God to reignite your passion, devotion, and love for Jesus.", category:"Faith", keywords:["prayer for revival","personal revival prayer","prayer for fire of God","prayer for awakening","prayer for spiritual renewal"], samplePrayer:"Lord, I am done with a lukewarm faith. Set me on fire again. Let the passion I had at first return with greater intensity. I am tired of going through motions — I want the real thing. Pour out Your Spirit on me. Let prayer become alive, worship become genuine, and service become urgent. Revive me again. In Jesus' name, Amen.", scripture:[{ref:"Psalm 85:6",text:"Will you not revive us again, that your people may rejoice in you?"},{ref:"Revelation 2:4-5",text:"You have forsaken the love you had at first. Consider how far you have fallen!"}], related:["spiritual-dryness","worship","faith","spiritual-growth","breakthrough"] },

  // ── DELIVERANCE & SPIRITUAL WARFARE ─────────────────────────────────

  { slug:"prayer-against-witchcraft", title:"Prayer Against Witchcraft and Occult", metaDesc:"A prayer for protection and deliverance from witchcraft, occult attacks, and spiritual forces of darkness.", category:"Faith", keywords:["prayer against witchcraft","prayer against occult","prayer for protection from witchcraft","prayer against black magic"], samplePrayer:"In the mighty name of Jesus Christ, I cancel every assignment of witchcraft, sorcery, divination, or occult practice sent against me. I renounce every evil covenant made over my life. The blood of Jesus is my covering. No weapon formed in the spirit realm against me shall prosper. Every arrow sent against me returns to the sender. I stand in the full armor of God. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 54:17",text:"No weapon formed against you will prevail."},{ref:"Galatians 5:20",text:"The acts of the flesh are obvious: witchcraft..."}], related:["deliverance","spiritual-warfare","protection","generational-curses","protection-from-enemies"] },

  { slug:"prayer-against-nightmares", title:"Prayer Against Nightmares", metaDesc:"A prayer against nightmares and disturbing dreams — for peaceful sleep and God's protection through the night.", category:"Faith", keywords:["prayer against nightmares","nightmare prayer","prayer for peaceful sleep","prayer against bad dreams"], samplePrayer:"Lord, my sleep belongs to You. I command every nightmare, every terrifying dream, every attack in the night season to cease. I plead the blood of Jesus over my mind as I sleep. Assign Your angels to watch over this room. Let my dreams be peaceful or purposeful — nothing harmful. I sleep in safety because You watch over me. In Jesus' name, Amen.", scripture:[{ref:"Psalm 4:8",text:"In peace I will lie down and sleep, for you alone, Lord, make me dwell in safety."},{ref:"Psalm 121:3",text:"He who watches over you will not slumber."}], related:["sleep","protection","spiritual-warfare","peace","anxiety"] },

  { slug:"prayer-for-enemies", title:"Prayer for Enemies and Those Who Hurt You", metaDesc:"A courageous prayer to bless your enemies — following Jesus' command to love and pray for those who persecute you.", category:"Relationships", keywords:["prayer for enemies","prayer for people who hurt you","prayer to forgive enemies","love your enemies prayer"], samplePrayer:"Jesus, You commanded us to pray for our enemies and bless those who curse us. This is one of the hardest things You ever asked. I bring the one who hurt me before You. I choose not to repay evil for evil. Bless them, Lord — with the only thing that can truly change them: encountering You. And heal what they broke in me. In Jesus' name, Amen.", scripture:[{ref:"Matthew 5:44",text:"Pray for those who persecute you."},{ref:"Romans 12:20",text:"If your enemy is hungry, feed him."}], related:["forgiveness","anger","reconciliation","love","healing"] },

  // ── YOUTH & STUDENTS ────────────────────────────────────────────────

  { slug:"back-to-school", title:"Prayer for Back to School", metaDesc:"A prayer for students returning to school — for safety, focus, good friendships, and academic success.", category:"Education", keywords:["prayer for back to school","back to school prayer","prayer for first day of school","prayer for new school year"], samplePrayer:"Lord, as a new school year begins, I cover this student in prayer. Protect them from bullying, from negative peer pressure, from every danger. Give them good teachers, good friends, and a focused mind. Let learning come with ease. And let their character grow as much as their knowledge. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 2:6",text:"For the Lord gives wisdom; from his mouth come knowledge and understanding."},{ref:"Daniel 1:17",text:"God gave knowledge and understanding to these four young men."}], related:["school","exam","teachers","children","youth-prayer"] },

  { slug:"youth-prayer", title:"Prayer for Youth and Young People", metaDesc:"A prayer for the youth generation — for purpose, identity, protection from the world's influences, and a strong faith.", category:"Education", keywords:["prayer for youth","youth prayer","prayer for teenagers","prayer for young people","prayer for generation z"], samplePrayer:"Lord, I pray for the youth of this generation — bombarded by social media, identity confusion, and a world that is louder than Your voice. Reach them where they are. Give them purpose so they don't wander. Give them identity in You so they don't accept counterfeits. Raise up the next generation of leaders, preachers, artists, and world changers. In Jesus' name, Amen.", scripture:[{ref:"1 Timothy 4:12",text:"Don't let anyone look down on you because you are young."},{ref:"Psalm 119:9",text:"How can a young person stay on the path of purity?"}], related:["school","exam","children","spiritual-growth","salvation"] },

  { slug:"college-student", title:"Prayer for College Students", metaDesc:"A prayer for students in college or university — for wisdom, protection, faith that survives campus culture, and academic excellence.", category:"Education", keywords:["prayer for college student","university prayer","prayer for college life","prayer for student away from home"], samplePrayer:"Lord, college is a season of tremendous opportunity and tremendous risk. I pray for every student on campus — that their faith would not collapse when it's tested. Give them wisdom to choose right, courage to stand out, discipline to study well, and community that builds rather than destroys. Let them graduate not just with a degree but with greater faith. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 4:7",text:"The beginning of wisdom is this: Get wisdom."},{ref:"Psalm 1:1",text:"Blessed is the one who does not walk in step with the wicked."}], related:["exam","school","youth-prayer","faith","spiritual-growth"] },

  { slug:"scholarship", title:"Prayer for a Scholarship", metaDesc:"A prayer for scholarship success — for favor with selection committees and God to provide for education costs.", category:"Education", keywords:["prayer for scholarship","scholarship prayer","prayer for financial aid","prayer for school fees","prayer for education funding"], samplePrayer:"Father, education opens doors and I need provision to walk through them. I pray for this scholarship application to find favor. Let the selection committee see something extraordinary. Supply what my family cannot. You are Jehovah Jireh — the Lord who provides. Let education be accessible, not out of reach. In Jesus' name, Amen.", scripture:[{ref:"Philippians 4:19",text:"My God will meet all your needs according to the riches of his glory."},{ref:"Matthew 7:7",text:"Ask and it will be given to you; seek and you will find."}], related:["exam","school","financial-breakthrough","favor","provision"] },

  { slug:"peer-pressure", title:"Prayer Against Peer Pressure", metaDesc:"A prayer for young people to withstand peer pressure — to stand firm in identity and make choices they will be proud of.", category:"Education", keywords:["prayer against peer pressure","peer pressure prayer","prayer for teenagers and peer pressure","prayer to resist temptation"], samplePrayer:"Lord, the pressure to fit in can feel unbearable. I pray for the courage to stand out when standing out is the right thing to do. Let the desire for Your approval outweigh the fear of rejection. Give this young person a backbone of conviction. Let them influence rather than be influenced. In Jesus' name, Amen.", scripture:[{ref:"Romans 12:2",text:"Do not conform to the pattern of this world."},{ref:"1 Peter 5:8",text:"Be self-controlled and alert."}], related:["youth-prayer","courage","faith","identity","spiritual-growth"] },

  { slug:"bullying", title:"Prayer for Victims of Bullying", metaDesc:"A prayer for children and young people who are being bullied — for God's protection, courage, and healing of emotional wounds.", category:"Education", keywords:["prayer for bullying","anti-bullying prayer","prayer for child being bullied","school bullying prayer"], samplePrayer:"Lord, the cruelty of bullying wounds the soul. I pray for every child and young person being bullied right now. May they know their worth is not defined by what others say. Give them protectors, allies, and at least one adult who takes it seriously. Stop the bullying at its source. And heal the wounds that cruel words have left behind. In Jesus' name, Amen.", scripture:[{ref:"Psalm 27:1",text:"The Lord is my light and my salvation — whom shall I fear?"},{ref:"Isaiah 54:17",text:"No weapon formed against you will prevail."}], related:["school","youth-prayer","healing","courage","protection"] },

  // ── SOCIAL & LIFE SITUATIONS ─────────────────────────────────────────

  { slug:"immigration", title:"Prayer for Immigrants and Refugees", metaDesc:"A prayer for immigrants, refugees, and asylum seekers — for safety, legal protection, and belonging in a new land.", category:"Nation", keywords:["prayer for immigrants","refugee prayer","prayer for asylum seekers","immigration prayer","prayer for deportation"], samplePrayer:"Lord, You Yourself were a refugee as a child — taken to Egypt for safety. You understand the experience of fleeing, of displacement, of rebuilding in a foreign land. I pray for every immigrant and refugee today. Grant legal protection. Open doors. Bring community and belonging. And let nations respond with the compassion You require. In Jesus' name, Amen.", scripture:[{ref:"Leviticus 19:34",text:"The foreigner residing among you must be treated as your native-born."},{ref:"Matthew 2:13",text:"Flee to Egypt and stay there until I tell you."}], related:["nation","justice","protection","comfort","hope"] },

  { slug:"homelessness", title:"Prayer for the Homeless", metaDesc:"A prayer for those experiencing homelessness — for shelter, dignity, and God's provision in their most desperate need.", category:"Nation", keywords:["prayer for homeless","homelessness prayer","prayer for people without homes","prayer for shelter"], samplePrayer:"Father, You are the One who gives the homeless a home — You said so in Your Word. I pray for every person sleeping outside tonight. Provide shelter. Restore dignity. Connect them with resources and people willing to help. And challenge the comfortable to be part of the solution. In Jesus' name, Amen.", scripture:[{ref:"Psalm 68:6",text:"God sets the lonely in families, he leads out the prisoners with singing."},{ref:"Isaiah 58:7",text:"Share your food with the hungry and provide the homeless with shelter."}], related:["provision","justice","nation","comfort","poverty"] },

  { slug:"poverty", title:"Prayer for Those in Poverty", metaDesc:"A prayer for those living in poverty — for God's miraculous provision, dignity, and a way forward.", category:"Nation", keywords:["prayer for poverty","prayer for the poor","prayer for financial poverty","prayer for those in need"], samplePrayer:"Lord, You said the poor will always be with us — but You also said blessed are the poor in spirit. I pray for those drowning in poverty right now. Provide daily bread in ways that defy natural explanation. Raise up their dignity. Open doors that seemed sealed shut. And move the hearts of those with resources to give generously. In Jesus' name, Amen.", scripture:[{ref:"Psalm 35:10",text:"Who rescues the poor from those too strong for them."},{ref:"Proverbs 19:17",text:"Whoever is kind to the poor lends to the Lord."}], related:["provision","financial-breakthrough","homeless","justice","blessing"] },

  { slug:"racial-healing", title:"Prayer for Racial Healing and Reconciliation", metaDesc:"A prayer for racial healing and reconciliation — for unity in diversity and the breaking down of walls that divide.", category:"Nation", keywords:["prayer for racial healing","racial reconciliation prayer","prayer against racism","prayer for unity in diversity"], samplePrayer:"Lord, You made every nation, every tribe, every tongue — and they are all beautiful in Your sight. The sin of racism is an offense to Your creative work. I pray for healing across racial divides. Give courage to the repentant, healing to the wounded, and wisdom to build bridges. Let the Church lead the way in unity. In Jesus' name, Amen.", scripture:[{ref:"Galatians 3:28",text:"There is neither Jew nor Gentile, neither slave nor free... for you are all one in Christ Jesus."},{ref:"Revelation 7:9",text:"A great multitude from every nation, tribe, people and language."}], related:["nation","justice","love","unity","peace"] },

  { slug:"prayer-for-elections", title:"Prayer for Elections and Voting", metaDesc:"A prayer for godly leadership through elections — for wisdom to vote, protection from corruption, and God's hand on governance.", category:"Nation", keywords:["prayer for elections","voting prayer","prayer before election","prayer for political leaders","election prayer"], samplePrayer:"Lord of nations, elections are in Your hands. I pray for this election season — for voters to choose wisely, for candidates to govern with integrity, for the process to be free and fair. Raise up leaders who fear You and serve the people. Expose corruption. Let justice be done. And remind us that no matter who wins, You are still on the throne. In Jesus' name, Amen.", scripture:[{ref:"Romans 13:1",text:"Let everyone be subject to the governing authorities, for there is no authority except that which God has established."},{ref:"Proverbs 29:2",text:"When the righteous thrive, the people rejoice."}], related:["nation","government","justice","prayer-for-leaders","peace"] },

  { slug:"prayer-for-leaders", title:"Prayer for Government Leaders", metaDesc:"A prayer for presidents, prime ministers, senators, and all government leaders — for wisdom, integrity, and godly governance.", category:"Nation", keywords:["prayer for government leaders","prayer for president","prayer for politicians","prayer for leaders of nations"], samplePrayer:"Lord, You set up kings and remove them. Today I pray for the leaders of this nation — that You would fill them with wisdom beyond their own. Where corruption tempts, give integrity. Where power intoxicates, give humility. Raise up counselors around them who speak truth. And where leaders are failing, raise up better ones. In Jesus' name, Amen.", scripture:[{ref:"1 Timothy 2:2",text:"Pray for kings and all those in authority, that we may live peaceful and quiet lives."},{ref:"Daniel 2:21",text:"He changes times and seasons; he deposes kings and raises up others."}], related:["nation","government","peace-in-the-world","justice","revival"] },

  { slug:"war-and-peace", title:"Prayer for War-Torn Nations", metaDesc:"A prayer for nations at war — for ceasefire, peace, protection of civilians, and God's intervention in conflict.", category:"Nation", keywords:["prayer for war","prayer for peace in nations","prayer for ceasefire","prayer for nations at war","prayer for peace"], samplePrayer:"Prince of Peace, the sounds of war are deafening and the images of destruction are devastating. I pray for war-torn nations — for the bombs to stop, for the guns to go silent, for negotiations to succeed where human pride has failed. Protect innocent civilians. Comfort the displaced. And let this conflict end in a peace that holds. In Jesus' name, Amen.", scripture:[{ref:"Psalm 46:9",text:"He makes wars cease to the ends of the earth."},{ref:"Isaiah 2:4",text:"Nation will not take up sword against nation, nor will they train for war anymore."}], related:["peace-in-the-world","military","nation","refugees","justice"] },

  { slug:"persecuted-christians", title:"Prayer for Persecuted Christians", metaDesc:"A prayer for Christians facing persecution around the world — for courage, protection, and the unstoppable spread of the Gospel.", category:"Nation", keywords:["prayer for persecuted Christians","persecution prayer","prayer for underground church","prayer for Christians in danger"], samplePrayer:"Lord, as I pray in freedom, believers around the world are praying at the risk of their lives. I stand with them. Protect the underground church. Give courage in interrogation rooms and prison cells. Let every attempt to silence the Gospel only amplify it. Let the Church flourish in the nations that try to kill it. In Jesus' name, Amen.", scripture:[{ref:"Matthew 5:10",text:"Blessed are those who are persecuted because of righteousness."},{ref:"Acts 4:29",text:"Enable your servants to speak your word with great boldness."}], related:["missionaries","revival","protection","courage","faith"] },

  // ── CHURCH & MINISTRY ────────────────────────────────────────────────

  { slug:"church-unity", title:"Prayer for Unity in the Church", metaDesc:"A prayer for unity among believers — breaking down division, denominations, and conflict within the body of Christ.", category:"Ministry", keywords:["prayer for church unity","prayer for unity in church","prayer against church division","church conflict prayer"], samplePrayer:"Father, Jesus prayed that we would be one as He and the Father are one. That prayer has not yet been fully answered — and I add my voice to it today. Break down the walls between denominations. Quiet the quarrels over secondary issues. Let love for one another become our greatest witness to the world. In Jesus' name, Amen.", scripture:[{ref:"John 17:21",text:"That all of them may be one, Father, just as you are in me and I am in you."},{ref:"Psalm 133:1",text:"How good and pleasant it is when God's people live together in unity!"}], related:["church","pastor","ministry","love","reconciliation"] },

  { slug:"worship-leaders", title:"Prayer for Worship Leaders", metaDesc:"A prayer for worship leaders — for anointing, humility, and the ability to lead people into God's presence.", category:"Ministry", keywords:["prayer for worship leaders","worship leader prayer","prayer for musicians","prayer for choir","prayer before worship"], samplePrayer:"Lord, anoint every worship leader who leads Your people in song. Let the music be more than production — let it be a vehicle for Your presence. Protect them from pride. Renew their devotion in private before they lead in public. And let every song played or sung this Sunday usher people into genuine encounter with You. In Jesus' name, Amen.", scripture:[{ref:"Psalm 22:3",text:"You are enthroned as the Holy One; you are the one Israel praises."},{ref:"Colossians 3:16",text:"Sing to God with gratitude in your hearts."}], related:["pastor","ministry","church","worship","revival"] },

  { slug:"before-preaching", title:"Prayer Before Preaching", metaDesc:"A prayer for preachers before delivering a sermon — for God's anointing, clarity, and the Word to land with power.", category:"Ministry", keywords:["prayer before preaching","preacher's prayer","prayer before sermon","prayer for anointing to preach"], samplePrayer:"Lord, let these words be Yours, not mine. Take my preparation and let the Holy Spirit breathe on it. Let every heart that needs to hear this message be in that room. Let distraction be silenced, hardness be softened, and let Your Word accomplish what You sent it to do. I decrease so You can increase in this moment. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 55:11",text:"My word will not return to me empty but will accomplish what I desire."},{ref:"Jeremiah 20:9",text:"His word is in my heart like a fire, a fire shut up in my bones."}], related:["pastor","ministry","church","revival","anointing"] },

  { slug:"missionaries-abroad", title:"Prayer for Missionaries Abroad", metaDesc:"A prayer for missionaries serving in foreign nations — for protection, fruit, open hearts, and supernatural provision.", category:"Ministry", keywords:["prayer for missionaries","missionary prayer","prayer for mission field","prayer for evangelism abroad"], samplePrayer:"Lord, I pray for missionaries who have left everything to carry Your name to the ends of the earth. Protect them from sickness, opposition, and discouragement. Give them language, culture, and relational wisdom. Let hearts be softened before they arrive. And let their sacrifice produce a harvest that outlasts their lifetime. In Jesus' name, Amen.", scripture:[{ref:"Romans 10:15",text:"How beautiful are the feet of those who bring good news!"},{ref:"Matthew 28:19",text:"Go and make disciples of all nations."}], related:["missionaries","ministry","revival","persecuted-christians","nation"] },

  // ── TRAVEL & SAFETY ─────────────────────────────────────────────────

  { slug:"prayer-before-flying", title:"Prayer Before Flying", metaDesc:"A prayer for safe air travel — for protection in the skies, peace of mind, and God's hand on every flight.", category:"Protection", keywords:["prayer before flying","airplane prayer","prayer for safe flight","fear of flying prayer","travel prayer"], samplePrayer:"Lord, I commend this flight into Your hands before it leaves the ground. Cover this aircraft, the pilots, the crew, and every passenger. Calm any anxiety about flying. Let turbulence not become terror. Protect us from every technical issue and every storm. Bring us safely to our destination at the appointed time. In Jesus' name, Amen.", scripture:[{ref:"Psalm 91:11",text:"He will command his angels concerning you to guard you in all your ways."},{ref:"Psalm 121:8",text:"The Lord will watch over your coming and going both now and forevermore."}], related:["travel","protection","peace","strength","faith"] },

  { slug:"safe-journey", title:"Prayer for a Safe Journey", metaDesc:"A prayer for protection during travel by road, air, or sea — for God's angels to guard every mile of the journey.", category:"Protection", keywords:["prayer for safe journey","road trip prayer","prayer before driving","travel prayer","prayer for safety on the road"], samplePrayer:"Lord, I am about to journey and I commit every mile to You. Let no accident, no breakdown, no danger interrupt this trip. Alert me when I need to be more careful. Keep other drivers from causing harm. Deliver me safely to my destination and bring me home again. Your angels go before me and behind me. In Jesus' name, Amen.", scripture:[{ref:"Psalm 121:7-8",text:"The Lord will keep you from all harm — he will watch over your life."},{ref:"Proverbs 3:23",text:"Then you will go on your way in safety, and your foot will not stumble."}], related:["travel","protection","prayer-before-flying","moving","faith"] },

  { slug:"visa-prayer", title:"Prayer for Visa and Immigration Approval", metaDesc:"A prayer for visa approval and immigration breakthrough — trusting God to open what governments can close.", category:"Protection", keywords:["prayer for visa","visa prayer","prayer for visa approval","prayer for green card","immigration prayer"], samplePrayer:"Lord, I stand before You with this application, this paperwork, this hope. Open the door that only You can open. Give favor with immigration officers. Let no paperwork be lost, no error disqualify, no officer's bad day block what You have ordained. You have authority over nations and their borders. Let my visa be approved. In Jesus' name, Amen.", scripture:[{ref:"Psalm 75:6-7",text:"Promotion comes neither from east nor west — but God is the judge."},{ref:"Proverbs 21:1",text:"The king's heart is in the hand of the Lord."}], related:["immigration","travel","favor","breakthrough","hope"] },

  // ── LEGAL & JUSTICE ─────────────────────────────────────────────────

  { slug:"court-case", title:"Prayer for a Court Case", metaDesc:"A prayer for justice and favor in a court case — trusting God to be your advocate, defender, and just judge.", category:"Nation", keywords:["prayer for court case","legal prayer","prayer for lawsuit","prayer for justice in court","prayer before going to court"], samplePrayer:"Lord, You are the just Judge of all the earth. I bring this case before You before I bring it before any earthly court. Give wisdom to my attorney. Let the truth be heard clearly. Let bias be neutralized. Grant favor with the judge. And let justice prevail — the way only You can ensure it. You are my defender. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 54:17",text:"No weapon formed against you will prevail... I will vindicate you."},{ref:"Psalm 37:6",text:"He will make your righteous reward shine like the dawn, your vindication like the noonday sun."}], related:["justice","protection","favor","breakthrough","nation"] },

  { slug:"prayer-for-prisoners", title:"Prayer for Those in Prison", metaDesc:"A prayer for men and women in prison — for safety, transformation, and the hope of a new chapter beyond their sentence.", category:"Nation", keywords:["prayer for prisoners","prison prayer","prayer for inmates","prayer for incarcerated","prayer for people in jail"], samplePrayer:"Lord, prison walls cannot contain Your presence or Your love. I pray for every person incarcerated right now. Meet them in their cell. Bring salvation, transformation, and purpose. Protect them from violence. And when their sentence ends, prepare a society ready to receive them, not just recycle them back in. In Jesus' name, Amen.", scripture:[{ref:"Psalm 102:20",text:"To hear the groans of the prisoners and release those condemned to death."},{ref:"Isaiah 61:1",text:"To proclaim freedom for the captives and release from darkness for the prisoners."}], related:["prison","nation","salvation","hope","deliverance"] },

  // ── PERSONAL GROWTH & CHARACTER ──────────────────────────────────────

  { slug:"pride", title:"Prayer Against Pride", metaDesc:"A prayer for humility — asking God to root out pride and replace it with a servant heart like Jesus.", category:"Faith", keywords:["prayer for humility","prayer against pride","prayer against arrogance","pride prayer"], samplePrayer:"Lord, pride is subtle and I am blind to much of mine. Search me and expose it. Deliver me from arrogance, from self-sufficiency, from the need to be right, from the addiction to applause. Clothe me in humility — the kind that does not think lowly of itself but does not need to think of itself at all. Make me like Jesus. In Jesus' name, Amen.", scripture:[{ref:"James 4:6",text:"God opposes the proud but shows favor to the humble."},{ref:"Proverbs 16:18",text:"Pride goes before destruction, a haughty spirit before a fall."}], related:["spiritual-growth","forgiveness","repentance","character","wisdom"] },

  { slug:"procrastination", title:"Prayer Against Procrastination", metaDesc:"A prayer for discipline and action — breaking the cycle of procrastination and doing what God has called you to do.", category:"Purpose", keywords:["prayer against procrastination","procrastination prayer","prayer for discipline","prayer for motivation"], samplePrayer:"Lord, the time You have given me is sacred and I have been wasting it. Break the paralysis of procrastination. Give me a sense of urgency without anxiety. Remind me that every day is a gift and every task done well is an act of worship. Let me be a person of action, not just intention. In Jesus' name, Amen.", scripture:[{ref:"Ephesians 5:16",text:"Make the most of every opportunity, because the days are evil."},{ref:"Proverbs 6:6",text:"Go to the ant, you sluggard; consider its ways and be wise!"}], related:["discipline","purpose","work","calling","strength"] },

  { slug:"discipline", title:"Prayer for Discipline and Self-Control", metaDesc:"A prayer for discipline and self-control — building consistent habits in faith, health, work, and character.", category:"Purpose", keywords:["prayer for discipline","self control prayer","prayer for consistency","prayer for willpower","prayer to build good habits"], samplePrayer:"Lord, knowledge without discipline produces nothing. Give me the self-control to act on what I know. Where I break promises to myself repeatedly, strengthen my will. Let discipline become a lifestyle rather than a struggle. Let consistency build into character. And let my life reflect the fruit of a Spirit-disciplined person. In Jesus' name, Amen.", scripture:[{ref:"2 Timothy 1:7",text:"God gave us a spirit of power, love and self-discipline."},{ref:"1 Corinthians 9:27",text:"I discipline my body and make it my slave."}], related:["strength","purpose","procrastination","spiritual-growth","work"] },

  { slug:"identity", title:"Prayer for Identity in Christ", metaDesc:"A prayer to know who you truly are in Christ — silencing lies and anchoring your identity in God's truth.", category:"Purpose", keywords:["prayer for identity","prayer for self worth","prayer for identity in Christ","prayer for insecurity","low self esteem prayer"], samplePrayer:"Father, the world has too many definitions of who I should be. I lay them all down. Tell me who I am. Not what I have done, not what has been done to me, not what others say — but who You say I am. Chosen. Loved. Called. Righteous. Redeemed. Sealed. Let that be the only identity I wear. In Jesus' name, Amen.", scripture:[{ref:"1 John 3:1",text:"See what great love the Father has lavished on us, that we should be called children of God!"},{ref:"Ephesians 1:4",text:"He chose us in him before the creation of the world."}], related:["purpose","spiritual-growth","faith","courage","healing"] },

  { slug:"comparison", title:"Prayer Against Comparison", metaDesc:"A prayer to stop comparing yourself to others — resting in the unique calling and timing God has for you.", category:"Purpose", keywords:["prayer against comparison","comparison prayer","prayer for contentment","prayer for jealousy","prayer against envy"], samplePrayer:"Lord, comparison is a thief — it steals my joy, my contentment, and my focus. Someone is always ahead. Someone always seems to have more. But You did not call me to run their race. Help me celebrate others without measuring myself against them. Root me in the unique purpose You have designed only for me. In Jesus' name, Amen.", scripture:[{ref:"Galatians 6:4",text:"Each one should test their own actions. Then they can take pride in themselves alone."},{ref:"2 Corinthians 10:12",text:"When they measure themselves by themselves and compare themselves with themselves, they are not wise."}], related:["identity","purpose","gratitude","peace","contentment"] },

  { slug:"contentment", title:"Prayer for Contentment", metaDesc:"A prayer to find peace and contentment in every season — learning the secret Paul discovered of being satisfied in God alone.", category:"Purpose", keywords:["prayer for contentment","contentment prayer","prayer to be satisfied","prayer against discontentment"], samplePrayer:"Lord, Paul said he learned to be content in all circumstances — not that it came naturally. Teach me that too. Let me be grateful for what I have while trusting You for what I need. Let wanting more not rob me of appreciating now. Whether in abundance or in lack, let contentment in You be my constant. In Jesus' name, Amen.", scripture:[{ref:"Philippians 4:11",text:"I have learned to be content whatever the circumstances."},{ref:"1 Timothy 6:6",text:"Godliness with contentment is great gain."}], related:["gratitude","peace","comparison","purpose","thanksgiving"] },

  { slug:"new-beginnings", title:"Prayer for New Beginnings", metaDesc:"A prayer for a fresh start — when God closes a chapter and opens a new one, trust Him to make all things new.", category:"Purpose", keywords:["prayer for new beginning","fresh start prayer","prayer for new chapter","prayer for starting over","new season prayer"], samplePrayer:"God of all new things, I stand at the doorway of a new beginning. I lay down the old — the failures, the regrets, the finished chapters — and I step forward with open hands. Make all things new in my life. Let this season be different. Let growth be real. Let this new beginning not just be a change of scenery but a change of heart. In Jesus' name, Amen.", scripture:[{ref:"Isaiah 43:19",text:"See, I am doing a new thing! Now it springs up; do you not perceive it?"},{ref:"Revelation 21:5",text:"He who was seated on the throne said, 'I am making everything new!'"}], related:["moving","purpose","hope","breakthrough","letting-go"] },

  { slug:"letting-go-of-past", title:"Prayer for Letting Go of the Past", metaDesc:"A prayer to release past hurts, failures, and regrets — and move forward in the freedom God provides.", category:"Purpose", keywords:["prayer for letting go","prayer to release the past","prayer for moving forward","prayer for past hurts","prayer to forgive yourself"], samplePrayer:"Lord, the past is a heavy bag I keep carrying into rooms it doesn't belong in. Give me the strength to set it down. The mistakes, the regrets, the what-ifs, the if-onlys — I release them all. You said You remember my sins no more — help me extend that same grace to myself. I am not my past. In Jesus' name, Amen.", scripture:[{ref:"Philippians 3:13",text:"Forgetting what is behind and straining toward what is ahead."},{ref:"Isaiah 43:25",text:"I am he who blots out your transgressions, for my own sake, and remembers your sins no more."}], related:["forgiveness","healing","new-beginnings","hope","trust"] },

  // ── SPECIAL OCCASIONS & PRAYER TYPES ────────────────────────────────

  { slug:"prayer-for-new-home", title:"Prayer for a New Home", metaDesc:"A prayer for dedicating and blessing a new home — inviting God's presence, peace, and protection into every room.", category:"Celebration", keywords:["prayer for new home","house blessing prayer","prayer to bless a house","new home prayer","house dedication prayer"], samplePrayer:"Lord, we dedicate this home to You. Let every room be filled with Your presence. Let peace rest between these walls. May this home be a place of love, laughter, hospitality, and healing. Where we eat, where we sleep, where we gather — let You be the head. Bless this house with Your glory. In Jesus' name, Amen.", scripture:[{ref:"Joshua 24:15",text:"As for me and my household, we will serve the Lord."},{ref:"Psalm 127:1",text:"Unless the Lord builds the house, the builders labor in vain."}], related:["moving","family","blessing","thanksgiving","protection"] },

  { slug:"prayer-before-meals", title:"Prayer Before Meals", metaDesc:"A simple, meaningful prayer before eating — giving thanks to God for His daily provision of food.", category:"Thanksgiving", keywords:["prayer before meals","grace before meals","prayer before eating","thanksgiving prayer for food","mealtime prayer"], samplePrayer:"Lord, thank You for this food. You are our daily bread — and this meal is evidence of Your faithfulness. Bless the hands that prepared it. Let it nourish and strengthen every body at this table. And let us never forget that millions go without. We eat with gratitude and with awareness of others. In Jesus' name, Amen.", scripture:[{ref:"Matthew 6:11",text:"Give us today our daily bread."},{ref:"1 Timothy 4:4",text:"Everything God created is good, and nothing is to be rejected if it is received with thanksgiving."}], related:["gratitude","thanksgiving","daily","provision","blessing"] },

  { slug:"intercessory-prayer", title:"Prayer of Intercession for Others", metaDesc:"A prayer of intercession — standing in the gap for others and lifting those we love before the throne of grace.", category:"Daily Prayer", keywords:["intercessory prayer","prayer for others","intercession prayer","standing in the gap prayer","prayer of intercession"], samplePrayer:"Lord, I come not for myself today but for others. I stand in the gap for those who may not know how to pray, who have stopped praying, or who are too weak to lift their own voices. Hear my intercession on their behalf. Move in their lives. Answer the prayers they haven't prayed yet. Let my prayers be arrows that find their mark. In Jesus' name, Amen.", scripture:[{ref:"Ezekiel 22:30",text:"I looked for someone among them who would build up the wall and stand before me in the gap."},{ref:"1 Timothy 2:1",text:"I urge first of all that petitions, prayers, intercession and thanksgiving be made for all people."}], related:["daily","morning","powerful-prayer","family","missionaries"] },

  { slug:"midnight-prayer", title:"Midnight Prayer", metaDesc:"A powerful prayer in the midnight hour — when Paul and Silas prayed at midnight and the chains fell off.", category:"Daily Prayer", keywords:["midnight prayer","prayer at midnight","3am prayer","night watch prayer","prayer in the night"], samplePrayer:"Lord, this is the midnight hour — and I am awake before You. Paul and Silas sang at midnight and the prison shook. Let my midnight prayer shake something too. Break every chain while the world sleeps. Perform Your miracles in the night season. I am awake because You are calling me to pray. I am here. In Jesus' name, Amen.", scripture:[{ref:"Acts 16:25",text:"About midnight Paul and Silas were praying and singing hymns to God."},{ref:"Psalm 119:62",text:"At midnight I rise to give you thanks for your righteous laws."}], related:["night","powerful-prayer","spiritual-warfare","breakthrough","daily"] },

  { slug:"declaration-prayer", title:"Prayer of Declaration", metaDesc:"A bold prayer of declaration — speaking God's promises over your life with faith and authority.", category:"Daily Prayer", keywords:["declaration prayer","prayer of declaration","speaking life prayer","prayer of affirmation","confessing the Word"], samplePrayer:"I declare by faith: I am blessed and not cursed. I am the head and not the tail. I am above and not beneath. No weapon formed against me shall prosper. I am healed. I am prosperous. I am protected. I am chosen. I am loved. I am called. God's plans for me are good. Today I agree with what God says about me. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 18:21",text:"The tongue has the power of life and death."},{ref:"Numbers 14:28",text:"I will do to you the very thing I heard you say."}], related:["powerful-prayer","faith","strength","hope","morning"] },

  { slug:"prayer-of-surrender", title:"Prayer of Surrender", metaDesc:"A prayer of complete surrender to God — releasing control and trusting Him with every area of your life.", category:"Faith", keywords:["prayer of surrender","surrender prayer","prayer to let go and let God","prayer of submission to God"], samplePrayer:"Lord, I give up. Not in defeat — but in surrender. I am done trying to control outcomes, manage impressions, and carry what only You can carry. I lay my plans, my fears, my relationships, my future — all of it — at Your feet. You know better. Your ways are higher. I trust You completely. I am Yours. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 3:5",text:"Trust in the Lord with all your heart and lean not on your own understanding."},{ref:"Luke 22:42",text:"Not my will, but yours be done."}], related:["trust","peace","faith","waiting-on-god","hope"] },

  { slug:"prayer-for-pastors-wife", title:"Prayer for the Pastor's Wife", metaDesc:"A prayer for the pastor's wife — she carries unique pressures and deserves specific prayer for strength, joy, and identity.", category:"Ministry", keywords:["prayer for pastors wife","first lady prayer","prayer for ministry spouse","prayer for church leaders wife"], samplePrayer:"Lord, the pastor's wife lives in a glass house, serves without a job title, and carries burdens most people never see. I pray for her today. Protect her heart from church hurt. Sustain her joy when it is drained. Give her an identity rooted in You — not in her husband's ministry. Let her be celebrated, not just used. In Jesus' name, Amen.", scripture:[{ref:"Proverbs 31:29",text:"Many women do noble things, but you surpass them all."},{ref:"Isaiah 40:31",text:"Those who hope in the Lord will renew their strength."}], related:["pastor","ministry","church","marriage","strength"] },

  { slug:"new-year-prayer", title:"Prayer for the New Year", metaDesc:"A powerful prayer as you enter a new year — surrendering the year ahead to God and declaring His goodness.", category:"Celebration", keywords:["new year prayer","prayer for new year","prayer to start the year","new years prayer","prayer for 2026"], samplePrayer:"Lord, as this new year opens, I bring it all to You. I cannot see what lies ahead — but You can. Order my steps. Guard my family. Prosper the work of my hands. Let this year be marked by growth, healing, breakthroughs, and deep encounters with You. Whatever comes — I face it with You. Happy New Year to the One who makes all things new. In Jesus' name, Amen.", scripture:[{ref:"Lamentations 3:22-23",text:"His mercies are new every morning; great is your faithfulness."},{ref:"Isaiah 43:19",text:"See, I am doing a new thing!"}], related:["morning","gratitude","purpose","hope","new-beginnings"] },

  { slug:"night-shift-prayer", title:"Prayer for Night Shift Workers", metaDesc:"A prayer for those who work through the night — for safety, alertness, and God's presence through the dark hours.", category:"Daily Prayer", keywords:["prayer for night shift","night shift prayer","prayer for overnight workers","prayer for nurses on night shift","prayer for security guards"], samplePrayer:"Lord, while the world sleeps, these faithful workers serve. I pray for everyone on the night shift — nurses, drivers, security, factory workers. Keep them alert and safe. Guard them from fatigue-related accidents. Let Your presence be their companion in the quiet hours. And bring them home safely when their shift ends. In Jesus' name, Amen.", scripture:[{ref:"Psalm 121:3-4",text:"He will not let your foot slip — he who watches over you will not slumber."},{ref:"Colossians 3:23",text:"Whatever you do, work at it with all your heart, as working for the Lord."}], related:["work","protection","night","daily","strength"] },

  { slug:"prayer-for-healing-relationship", title:"Prayer for Healing a Relationship", metaDesc:"A prayer to heal a broken relationship — between friends, family members, or estranged loved ones.", category:"Relationships", keywords:["prayer for healing a relationship","prayer for broken friendship","prayer for estranged family","prayer to restore a relationship"], samplePrayer:"Lord, this relationship has been wounded — by words, by misunderstanding, by time, by pride. I pray for restoration. Soften hearts on both sides. Give us the courage to have the hard conversation. Let forgiveness flow. Not all relationships can be restored the same way — but let healing happen in every case, even if the relationship changes. In Jesus' name, Amen.", scripture:[{ref:"Matthew 5:23-24",text:"First go and be reconciled to them; then come and offer your gift."},{ref:"Proverbs 17:17",text:"A friend loves at all times, and a brother is born for a time of adversity."}], related:["forgiveness","reconciliation","friendship","love","healing"] },

  { slug:"anxiety-at-night", title:"Prayer for Anxiety at Night", metaDesc:"A prayer for those who lie awake anxious at night — for God's peace to silence racing thoughts and grant rest.", category:"Mental Health", keywords:["prayer for anxiety at night","nighttime anxiety prayer","prayer for racing thoughts","prayer to sleep despite anxiety"], samplePrayer:"Lord, it is night and my mind will not be still. Every worry that seemed manageable in the day is amplified in the dark. I give You each thought, one by one. You are already in my tomorrow — it is handled. Let that truth slow my racing mind. Replace the anxiety with Your peace that surpasses understanding. Let sleep come and let rest be real. In Jesus' name, Amen.", scripture:[{ref:"Psalm 127:2",text:"He grants sleep to those he loves."},{ref:"1 Peter 5:7",text:"Cast all your anxiety on him because he cares for you."}], related:["anxiety","sleep","night","peace","stress"] },

  { slug:"prayer-for-healing-heart", title:"Prayer for a Broken Heart", metaDesc:"A prayer for healing a broken heart — from loss, rejection, or heartbreak. God is close to the brokenhearted.", category:"Grief", keywords:["prayer for broken heart","heartbreak prayer","prayer for heartbreak","prayer for rejection","prayer after break up"], samplePrayer:"Lord, this heart is broken and I cannot fix it. The pain sits heavy and refuses to pass quickly. But You said You are close to the brokenhearted — so I believe You are close right now. Mend what has been torn. Take the shattered pieces and create something beautiful from them. Let time and Your presence work together to heal this wound. In Jesus' name, Amen.", scripture:[{ref:"Psalm 34:18",text:"The Lord is close to the brokenhearted and saves those who are crushed in spirit."},{ref:"Psalm 147:3",text:"He heals the brokenhearted and binds up their wounds."}], related:["grief","healing","love","comfort","hope"] },

  { slug:"health-discipline", title:"Prayer for Health and Fitness Discipline", metaDesc:"A prayer for the discipline to exercise, eat well, and maintain the health God designed for your body.", category:"Health", keywords:["prayer for health","prayer for fitness","prayer to exercise","prayer for healthy habits","prayer for diet discipline"], samplePrayer:"Lord, my body is Your temple and I want to steward it well. Give me the discipline to move it, to feed it wisely, and to rest it properly. When motivation fails, let conviction carry me. Let every healthy choice be an act of worship. And let the energy that comes from good health fuel the purpose You have for my life. In Jesus' name, Amen.", scripture:[{ref:"1 Corinthians 6:19-20",text:"Your bodies are temples of the Holy Spirit. Honor God with your bodies."},{ref:"3 John 1:2",text:"Dear friend, I pray that you may enjoy good health."}], related:["healing","weight-loss","discipline","strength","purpose"] },

  { slug:"prayer-for-salvation-of-family", title:"Prayer for the Salvation of Family Members", metaDesc:"A prayer for unsaved family members — trusting God to reach those we love most with the Gospel.", category:"Salvation", keywords:["prayer for family salvation","prayer for unsaved family","prayer for lost loved ones","prayer for family members to be saved"], samplePrayer:"Lord, I cannot rest while those I love most do not know You. I pray for my unsaved family members by name before Your throne. Frustrate every distraction that keeps them from encountering You. Send the right person, the right sermon, the right crisis that leads them to call on Your name. Let our family be fully Yours. In Jesus' name, Amen.", scripture:[{ref:"Acts 16:31",text:"Believe in the Lord Jesus, and you will be saved — you and your household."},{ref:"Romans 10:1",text:"Brothers and sisters, my heart's desire and prayer to God for them is that they may be saved."}], related:["salvation","family","faith","revival","intercession"] },

  { slug:"prayer-for-dreams-goals", title:"Prayer for Dreams and Goals", metaDesc:"A prayer to commit your dreams and goals to God — for His guidance, favor, and supernatural acceleration.", category:"Purpose", keywords:["prayer for dreams","prayer for goals","prayer for vision","prayer for ambition","prayer for life goals"], samplePrayer:"Lord, You put these dreams in me — or I ask You to purify them if they are just my own desires. Either way, I submit them to You. Order the steps to get there. Give me the right mentors, the right timing, and the right doors. Let hard work and Your blessing meet. And when I achieve these goals, let them bring You glory and others benefit. In Jesus' name, Amen.", scripture:[{ref:"Psalm 20:4",text:"May he give you the desire of your heart and make all your plans succeed."},{ref:"Habakkuk 2:2",text:"Write down the revelation and make it plain on tablets so that a herald may run with it."}], related:["purpose","calling","direction","faith","breakthrough"] },

];
